export async function syncLatestCatalog() {
  await new Promise((resolve) => setTimeout(resolve, 1500));

  syncRun += 1;
  const inventoryOffset = syncRun % 4;

  products = products.map((product, index) => {
    const priceDelta = ((syncRun + index) % 3) * 5;
    const nextInventory = Math.max(
      0,
      product.inventory + inventoryOffset * 3 - (index % 3) * 4,
    );

    let availability = "In stock";
    if (nextInventory === 0) {
      availability = "Out of stock";
    } else if (nextInventory < 12) {
      availability = "Low stock";
    }

    return {
      ...product,
      price: product.price + priceDelta,
      inventory: nextInventory,
      availability,
    };
  });

  lastSyncedAt = new Date().toISOString();
}


